impl CollateralCriteriaBase for crate::CollateralCriteriaBaseOrSubtype {
        fn collateralCriteria<'a>(&'a self) -> Option<&'a crate::CurrencyCodeEnum> {
        match self {
                CollateralCriteriaBaseOrSubtype::EligibleCollateralCriteria(val) => val.collateralCriteria(),
                CollateralCriteriaBaseOrSubtype::ConcentrationLimitCriteria(val) => val.collateralCriteria(),

        }
    }
        fn appliesTo<'a>(&'a self) -> Option<impl poly_containers::SeqRef<'a, crate::CounterpartyRoleEnum>> {
        match self {
                CollateralCriteriaBaseOrSubtype::EligibleCollateralCriteria(val) => val.appliesTo().map(|x| x.to_any()),
                CollateralCriteriaBaseOrSubtype::ConcentrationLimitCriteria(val) => val.appliesTo().map(|x| x.to_any()),

        }
    }
        fn restrictTo<'a>(&'a self) -> Option<&'a crate::CollateralMarginTypeEnum> {
        match self {
                CollateralCriteriaBaseOrSubtype::EligibleCollateralCriteria(val) => val.restrictTo(),
                CollateralCriteriaBaseOrSubtype::ConcentrationLimitCriteria(val) => val.restrictTo(),

        }
    }
        fn ratingPriorityResolution<'a>(&'a self) -> Option<&'a crate::RatingPriorityResolutionEnum> {
        match self {
                CollateralCriteriaBaseOrSubtype::EligibleCollateralCriteria(val) => val.ratingPriorityResolution(),
                CollateralCriteriaBaseOrSubtype::ConcentrationLimitCriteria(val) => val.ratingPriorityResolution(),

        }
    }
}

