    // fn reset_mut(&mut self) -> &mut Option<bool>;
    // fn set_reset(&mut self, value: Option<bool>);

    fn futureValueNotional<'a>(&'a self) -> Option<&'a crate::FutureValueAmount>;
    // fn futureValueNotional_mut(&mut self) -> &mut Option<&'a crate::FutureValueAmount>;
