impl PayoutBase for crate::PayoutBaseOrSubtype {
        fn payerReceiver<'a>(&'a self) -> &'a PayerReceiverOrSubtype {
        match self {
                PayoutBaseOrSubtype::CommodityPayout(val) => val.payerReceiver(),
                PayoutBaseOrSubtype::CreditDefaultPayout(val) => val.payerReceiver(),
                PayoutBaseOrSubtype::InterestRatePayout(val) => val.payerReceiver(),
                PayoutBaseOrSubtype::OptionPayout(val) => val.payerReceiver(),
                PayoutBaseOrSubtype::PerformancePayout(val) => val.payerReceiver(),
                PayoutBaseOrSubtype::SettlementPayout(val) => val.payerReceiver(),
                PayoutBaseOrSubtype::FixedPricePayout(val) => val.payerReceiver(),
                PayoutBaseOrSubtype::AssetPayout(val) => val.payerReceiver(),

        }
    }
        fn priceQuantity<'a>(&'a self) -> Option<&'a crate::ResolvablePriceQuantity> {
        match self {
                PayoutBaseOrSubtype::CommodityPayout(val) => val.priceQuantity(),
                PayoutBaseOrSubtype::CreditDefaultPayout(val) => val.priceQuantity(),
                PayoutBaseOrSubtype::InterestRatePayout(val) => val.priceQuantity(),
                PayoutBaseOrSubtype::OptionPayout(val) => val.priceQuantity(),
                PayoutBaseOrSubtype::PerformancePayout(val) => val.priceQuantity(),
                PayoutBaseOrSubtype::SettlementPayout(val) => val.priceQuantity(),
                PayoutBaseOrSubtype::FixedPricePayout(val) => val.priceQuantity(),
                PayoutBaseOrSubtype::AssetPayout(val) => val.priceQuantity(),

        }
    }
        fn principalPayment<'a>(&'a self) -> Option<&'a crate::PrincipalPayments> {
        match self {
                PayoutBaseOrSubtype::CommodityPayout(val) => val.principalPayment(),
                PayoutBaseOrSubtype::CreditDefaultPayout(val) => val.principalPayment(),
                PayoutBaseOrSubtype::InterestRatePayout(val) => val.principalPayment(),
                PayoutBaseOrSubtype::OptionPayout(val) => val.principalPayment(),
                PayoutBaseOrSubtype::PerformancePayout(val) => val.principalPayment(),
                PayoutBaseOrSubtype::SettlementPayout(val) => val.principalPayment(),
                PayoutBaseOrSubtype::FixedPricePayout(val) => val.principalPayment(),
                PayoutBaseOrSubtype::AssetPayout(val) => val.principalPayment(),

        }
    }
        fn settlementTerms<'a>(&'a self) -> Option<&'a crate::SettlementTerms> {
        match self {
                PayoutBaseOrSubtype::CommodityPayout(val) => val.settlementTerms(),
                PayoutBaseOrSubtype::CreditDefaultPayout(val) => val.settlementTerms(),
                PayoutBaseOrSubtype::InterestRatePayout(val) => val.settlementTerms(),
                PayoutBaseOrSubtype::OptionPayout(val) => val.settlementTerms(),
                PayoutBaseOrSubtype::PerformancePayout(val) => val.settlementTerms(),
                PayoutBaseOrSubtype::SettlementPayout(val) => val.settlementTerms(),
                PayoutBaseOrSubtype::FixedPricePayout(val) => val.settlementTerms(),
                PayoutBaseOrSubtype::AssetPayout(val) => val.settlementTerms(),

        }
    }
}

